var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>익명으로 수신한 메일입니다.</color>`,JPN:`<color=#ffd34c>匿名の送信者から受信したメールです。</color>`,ENG:`<color=#ffd34c>An anonymous mail arrived.</color>`,TWN:`<color=#ffd34c>匿名收取的郵件</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`특정 공간 좌표에서의 대 침식전을 의뢰한다.`,JPN:`特定空間座標における対侵食戦を依頼する。`,ENG:`This is a request for an anti-Corruption battle at a specific spatial coordinates.`,TWN:`委託在特定空間座標進行侵蝕戰。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`내용은 간단하다. 우리 측 조사대가 안전하게 활동할 수 있게 모든 침식체 군집을 와해하면 된다.`,JPN:`内容は簡単だ。調査隊が安全に活動できるように、
侵食体の群れを全て追い払ってくれればいい。`,ENG:`The mission is simple. Disperse all C.O. groups in the area to secure the safety of our investigation team.`,TWN:`內容很簡單，瓦解所有侵蝕體的攻勢，保障韓國方的調查隊能夠安全地進行活動。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`착오가 없게 덧붙이자면, 군집을 형성하는 우두머리만 제거해 달라는 뜻이다.`,JPN:`手違いが無いように付け加えると、群れを形成するボスを倒してほしいという意味だ。`,ENG:`To be clear, I want you to get rid of the C.O. boss that is forming the group.`,TWN:`如果沒有錯的話，這意味著你只要清除掉那個能夠形成群落的首領就行了。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`공간 좌표는 별도의 채널로 보낼 예정이다. 긍정적인 답변을 기대하지.`,JPN:`空間座標は別のチャンネルから送る予定だ。前向きな返答を待っている。`,ENG:`The spatial coordinates will be sent via a separate channel. I hope to hear a positive answer from you.`,TWN:`空間座標將通過其他頻道發送過去。期待你的好消息。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};